-- ─────────────────────────────────────────────────────────────────────────────
-- Restore gamepasses for games affected by the Import Catalog bug, from the
-- original spreadsheet. Generated by scripts/restore-catalog.mjs — parsing
-- logic is identical to src/lib/utils/pricingEngine.ts.
--
-- Wipes ONLY the games listed below, then recreates their gamepasses fresh.
-- Any other game in your catalog is untouched.
-- ─────────────────────────────────────────────────────────────────────────────

DO $$
DECLARE
  v_user_id uuid;
BEGIN
  SELECT user_id INTO v_user_id FROM public.games LIMIT 1;
  IF v_user_id IS NULL THEN RAISE EXCEPTION 'No existing games row found to infer user_id from'; END IF;

  SELECT v_user_id, 'Slime rng'
  WHERE NOT EXISTS (SELECT 1 FROM public.games WHERE user_id = v_user_id AND name = 'Slime rng');

  SELECT v_user_id, 'KICK A LUCKY BLOCK (done)'
  WHERE NOT EXISTS (SELECT 1 FROM public.games WHERE user_id = v_user_id AND name = 'KICK A LUCKY BLOCK (done)');

  SELECT v_user_id, 'anime vanguards (top 1)'
  WHERE NOT EXISTS (SELECT 1 FROM public.games WHERE user_id = v_user_id AND name = 'anime vanguards (top 1)');

  SELECT v_user_id, 're:rangers X'
  WHERE NOT EXISTS (SELECT 1 FROM public.games WHERE user_id = v_user_id AND name = 're:rangers X');

  SELECT v_user_id, 'survive the apocalypse'
  WHERE NOT EXISTS (SELECT 1 FROM public.games WHERE user_id = v_user_id AND name = 'survive the apocalypse');

  SELECT v_user_id, 'catch and tame'
  WHERE NOT EXISTS (SELECT 1 FROM public.games WHERE user_id = v_user_id AND name = 'catch and tame');

  SELECT v_user_id, 'drag simulator'
  WHERE NOT EXISTS (SELECT 1 FROM public.games WHERE user_id = v_user_id AND name = 'drag simulator');

  SELECT v_user_id, 'Wizard Alchemy'
  WHERE NOT EXISTS (SELECT 1 FROM public.games WHERE user_id = v_user_id AND name = 'Wizard Alchemy');

  SELECT v_user_id, 'Strongest Battlegrounds'
  WHERE NOT EXISTS (SELECT 1 FROM public.games WHERE user_id = v_user_id AND name = 'Strongest Battlegrounds');

  SELECT v_user_id, 'EVADE'
  WHERE NOT EXISTS (SELECT 1 FROM public.games WHERE user_id = v_user_id AND name = 'EVADE');

  SELECT v_user_id, 'Anime Warriors III'
  WHERE NOT EXISTS (SELECT 1 FROM public.games WHERE user_id = v_user_id AND name = 'Anime Warriors III');

  SELECT v_user_id, 'Anime Fighting Simulator Endless'
  WHERE NOT EXISTS (SELECT 1 FROM public.games WHERE user_id = v_user_id AND name = 'Anime Fighting Simulator Endless');

  SELECT v_user_id, 'CDID'
  WHERE NOT EXISTS (SELECT 1 FROM public.games WHERE user_id = v_user_id AND name = 'CDID');

  SELECT v_user_id, 'Hypershot'
  WHERE NOT EXISTS (SELECT 1 FROM public.games WHERE user_id = v_user_id AND name = 'Hypershot');

  SELECT v_user_id, 'Keyboard Escape | Candy & Chocolate'
  WHERE NOT EXISTS (SELECT 1 FROM public.games WHERE user_id = v_user_id AND name = 'Keyboard Escape | Candy & Chocolate');

  SELECT v_user_id, 'Build a ring farm'
  WHERE NOT EXISTS (SELECT 1 FROM public.games WHERE user_id = v_user_id AND name = 'Build a ring farm');

  SELECT v_user_id, 'Grow a garden 2'
  WHERE NOT EXISTS (SELECT 1 FROM public.games WHERE user_id = v_user_id AND name = 'Grow a garden 2');

  SELECT v_user_id, 'keme'
  WHERE NOT EXISTS (SELECT 1 FROM public.games WHERE user_id = v_user_id AND name = 'keme');

  SELECT v_user_id, 'Redliner'
  WHERE NOT EXISTS (SELECT 1 FROM public.games WHERE user_id = v_user_id AND name = 'Redliner');

  SELECT v_user_id, 'Midnight chasers'
  WHERE NOT EXISTS (SELECT 1 FROM public.games WHERE user_id = v_user_id AND name = 'Midnight chasers');

  DELETE FROM public.gamepasses
  WHERE user_id = v_user_id
    AND game_id IN (
      SELECT id FROM public.games WHERE user_id = v_user_id AND name IN (
        'Slime rng',
        'KICK A LUCKY BLOCK (done)',
        'anime vanguards (top 1)',
        're:rangers X',
        'survive the apocalypse',
        'catch and tame',
        'drag simulator',
        'Wizard Alchemy',
        'Strongest Battlegrounds',
        'EVADE',
        'Anime Warriors III',
        'Anime Fighting Simulator Endless',
        'CDID',
        'Hypershot',
        'Keyboard Escape | Candy & Chocolate',
        'Build a ring farm',
        'Grow a garden 2',
        'keme',
        'Redliner',
        'Midnight chasers'
      )
    );


END $$;
